import requests

headers = {"API-Key" : "<add_your_key>"}

params = {
  "latitude" : "-45",
  "longitude" : "45"
}

# Make the API call
try:
  response = requests.get(
    "https://gravity.amentum.io/egm2008/geoid_height",
    params=params, headers=headers)
  response_json = response.json()
  response.raise_for_status()
except requests.exceptions.HTTPError as e:
  print(response_json['error'])
else:
  # Extract the height
  height = response_json['height']['value']
  h_unit = response_json['height']['units']
  print("Height: ", height, h_unit)

fetch("https://gravity.amentum.io/egm2008/geoid_height?latitude=-45&longitude=45", {
  method: "GET",
  headers: {
    "API-Key": "<your_key>",
    "Accept": "application/json"
  }
})
.then(response => response.json())
.then(data => console.log("Height:", data.height.value, data.height.units))
.catch(error => console.error("Error:", error));

import java.io.*;
import java.net.*;

public class Main {
  public static void main(String[] args) throws IOException {
    URL url = new URL("https://gravity.amentum.io/egm2008/geoid_height?latitude=-45&longitude=45");
    HttpURLConnection con = (HttpURLConnection) url.openConnection();
    con.setRequestMethod("GET");
    con.setRequestProperty("API-Key", "<your_key>");
    con.setRequestProperty("Accept", "application/json");

    BufferedReader in = new BufferedReader(new InputStreamReader(con.getInputStream()));
    String inputLine;
    StringBuffer content = new StringBuffer();
    while ((inputLine = in.readLine()) != null) {
      content.append(inputLine);
    }
    in.close();
    System.out.println(content.toString());
  }
}

#include <iostream>
#include <curl/curl.h>

static size_t WriteCallback(void *contents, size_t size, size_t nmemb, void *userp) {
    ((std::string*)userp)->append((char*)contents, size * nmemb);
    return size * nmemb;
}

int main() {
    CURL *curl;
    CURLcode res;
    std::string readBuffer;

    curl = curl_easy_init();
    if(curl) {
        curl_easy_setopt(curl, CURLOPT_URL, "https://gravity.amentum.io/egm2008/geoid_height?latitude=-45&longitude=45");
        curl_easy_setopt(curl, CURLOPT_HTTPHEADER, "<your_key>");
        curl_easy_setopt(curl, CURLOPT_WRITEFUNCTION, WriteCallback);
        curl_easy_setopt(curl, CURLOPT_WRITEDATA, &readBuffer);
        res = curl_easy_perform(curl);
        curl_easy_cleanup(curl);

        std::cout << readBuffer << std::endl;
    }
    return 0;
}

import Foundation

if let url = URL(string: "https://gravity.amentum.io/egm2008/geoid_height?latitude=-45&longitude=45") {
    var request = URLRequest(url: url)
    request.addValue("<your_key>", forHTTPHeaderField: "API-Key")
    request.addValue("application/json", forHTTPHeaderField: "accept")

    URLSession.shared.dataTask(with: request) { data, response, error in
        guard let data = data, error == nil else { return }
        if let heightResponse = try? JSONDecoder().decode(HeightResponse.self, from: data) {
            print("Height:", heightResponse.height.value, heightResponse.height.units)
        }
    }.resume()
}

struct HeightResponse: Codable {
    struct Height: Codable {
        let value: Double
        let units: String
    }
    let height: Height
}

